.services-intro { max-width: 720px; margin: 0 auto; }
.services-intro h1 { font-size: clamp(1.75rem, 3vw, 2.5rem); margin-bottom: 1rem; }
.services-intro h2 { font-size: 1.4rem; margin-top: 2.5rem; margin-bottom: 0.5rem; border-left: 4px solid var(--color-primary, #2563eb); padding-left: 0.75rem; }
.services-intro ul { padding-left: 1.25rem; }
.services-intro li { margin-bottom: 0.4rem; }
